import { spawn, spawnSync } from "node:child_process";

/**
 * Dev server orchestrator — mirrors the shape of checks.ts.
 *
 * Runs the library build synchronously first (ensures dist/ and
 * dist/docgen.json exist before the explorer dev server starts),
 * then launches the lib watch and explorer dev server concurrently.
 */

console.log("▶ Building @imfusion/web-ui...\n");
const build = spawnSync("npm", ["run", "build", "-w", "packages/web-ui"], { stdio: "inherit" });

if (build.status !== 0) {
  console.error("\n✗ Build failed — fix errors above before starting dev server.");
  process.exit(build.status ?? 1);
}

console.log("\n✓ Build complete — starting dev servers\n");

const explorerScript = process.argv.includes("--host") ? "dev:host" : "dev";

const proc = spawn(
  "npx",
  [
    "concurrently",
    "--names",
    "lib,app",
    "--prefix-colors",
    "blue,green",
    "npm run dev -w packages/web-ui",
    `npm run ${explorerScript} -w apps/explorer`
  ],
  { stdio: "inherit", shell: false }
);

proc.on("close", code => {
  process.exit(code ?? 0);
});

["SIGINT", "SIGTERM"].forEach(signal => {
  process.on(signal, () => {
    proc.kill(signal as NodeJS.Signals);
  });
});
